import java.util.Arrays;

/**
 * https://leetcode.com/problems/largest-palindromic-number/
 * 
 *  Output:
 *  ------
 *  7449447
 *  9
 *  1
 *  0
 *  6006
 */

public class LongestPalindromicNumber {

	
	public String largestPalindromic(String num) {
        String frontStr = "", backStr = "", result = "";
        int[] count = new int[10];
        int maxOdd = -1;
        
        for (int i = 0; i < num.length(); i++) {
        	int val = Integer.valueOf(num.charAt(i) - '0');
        	count[val]++;
        }
        
        for (int i = 9; i >= 0; i--) {
        	if (count[i] % 2 == 0) {
        		for (int j = 0; j < count[i]/2; j++) {
        			frontStr += String.valueOf(i);
        			backStr = String.valueOf(i) + backStr;
        		}
        	} else {
        		if (maxOdd == -1) {
        			maxOdd = i;
        		}
        		for (int j = 0; j < count[i]/2; j++) {
        			frontStr += String.valueOf(i);
        			backStr = String.valueOf(i) + backStr;
        		}
        	}
        }
        
        if (maxOdd != -1) {
        	result = frontStr + String.valueOf(maxOdd) + backStr;
        } else {
        	result = frontStr + backStr;
        }
        
        while (result.charAt(0) == '0' && result.length() > 1) {
        	if (result.length() == 2) {
        		result = "0";
        		break;
        	}
        	result = result.substring(1, result.length()-1);
        }
        
        return result;
    }

	public static void main(String[] args) {
		System.out.println(new LongestPalindromicNumber().largestPalindromic("444947137"));
		System.out.println(new LongestPalindromicNumber().largestPalindromic("00009"));
		System.out.println(new LongestPalindromicNumber().largestPalindromic("1"));
		System.out.println(new LongestPalindromicNumber().largestPalindromic("00000"));
		System.out.println(new LongestPalindromicNumber().largestPalindromic("6006"));
		// System.out.println(new LongestPalindromicNumber().largestPalindromic(""));
	}

}
